import { BOX_SIZE, SUDOKU_SIZE } from '@sudoku/constants';
import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { derived, writable } from 'svelte/store';
import { hints } from './hints';
// 导入我们的领域对象（注意路径！如果你的domain文件夹在src/lib下，就用这个路径）
import { Game } from '$lib/domain/Game';
import { Sudoku } from '$lib/domain/Sudoku';

// ====================== 第一步：重构核心 - 用领域对象替代原始数组 ======================
function createGameStore() {
  // 初始化空的数独领域对象
  const initialGrid = Array(SUDOKU_SIZE).fill().map(() => Array(SUDOKU_SIZE).fill(0));
  const initialSudoku = new Sudoku(initialGrid);
  const initialGame = new Game(initialSudoku);

  const { subscribe, set, update } = writable(initialGame);

  return {
    subscribe,
    
    // 生成新游戏（适配原有 generate 接口）
    generate(difficulty) {
      const newGrid = generateSudoku(difficulty);
      const newSudoku = new Sudoku(newGrid);
      set(new Game(newSudoku));
    },

    // 解码 sencode（适配原有 decodeSencode 接口）
    decodeSencode(sencode) {
      const newGrid = decodeSencode(sencode);
      const newSudoku = new Sudoku(newGrid);
      set(new Game(newSudoku));
    },

    // 填数（核心！替代原有 userGrid.set）
    guess(x, y, value) {
      update(game => game.guess(y, x, value)); // 注意：领域对象是 (row, col) = (y, x)
    },

    // 应用提示（适配原有 applyHint 接口）
    applyHint(x, y) {
      update(game => {
        hints.useHint();
        const currentGrid = game.sudoku.getUserGrid();
        const solvedGrid = solveSudoku(currentGrid);
        return game.guess(y, x, solvedGrid[y][x]);
      });
    },

    // Undo/Redo（暴露给 game store 使用）
    undo: () => update(game => game.undo()),
    redo: () => update(game => game.redo()),

    // 获取 sencode（适配原有接口）
    getSencode(game) {
      return encodeSudoku(game.sudoku.getUserGrid());
    },

    // 获取单个格子值（适配原有接口）
    get(game, x, y) {
      return game.sudoku.getUserGrid()[y][x];
    }
  };
}

// 创建核心游戏 store（持有领域对象）
const gameStore = createGameStore();

// ====================== 第二步：适配原有对外接口 - 完全保留原有导出 ======================

// 1. 原有 grid store（固定初始盘）
export const grid = {
  subscribe: derived(gameStore, $game => $game.sudoku.getFixedGrid()).subscribe,
  
  generate: (difficulty) => gameStore.generate(difficulty),
  
  decodeSencode: (sencode) => gameStore.decodeSencode(sencode),
  
  get: ($grid, x, y) => gameStore.get({ sudoku: { getUserGrid: () => $grid } }, x, y),
  
  getSencode: ($grid) => gameStore.getSencode({ sudoku: { getUserGrid: () => $grid } })
};

// 2. 原有 userGrid store（用户当前盘）
export const userGrid = {
  subscribe: derived(gameStore, $game => $game.sudoku.getUserGrid()).subscribe,
  
  set: (pos, value) => gameStore.guess(pos.x, pos.y, value),
  
  applyHint: (pos) => gameStore.applyHint(pos.x, pos.y)
};

// 3. 原有 invalidCells store（冲突单元格）
export const invalidCells = derived(gameStore, $game => {
  return $game.sudoku.getInvalidCellsArray();
}, []);

// ====================== 第三步：暴露领域对象操作给 Undo/Redo ======================
// 供 game.js 调用 undo/redo
export const domainGameApi = {
  undo: () => gameStore.undo(),
  redo: () => gameStore.redo()
};
